request.query:
BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?activityName (COUNT(?node) as ?nodeCount) (COUNT(?edge) as ?edgeCount) WHERE {
  ?activity vocab:NamedElement_name ?activityName .
  FILTER(CONTAINS(LCASE(STR(?activityName)), "aps"))
  ?activity rdf:type vocab:activity .
  OPTIONAL { ?activity vocab:Activity_node ?node }
  OPTIONAL { ?activity vocab:Activity_edge ?edge }
}
GROUP BY ?activityName
ORDER BY DESC(?nodeCount)
LIMIT 20
